import type { Targetable } from "bitfab-flow";
/**
 * Single source of truth for every AI framework Bitfab has first-class
 * instrumentation support for. All per-framework prose in the flows (detection
 * signals, docs-page routing, handler/processor/wrapper names, replay guidance,
 * the SDK grep patterns) is DERIVED from this table via the builders below and
 * surfaced as flow variables in `FRAMEWORK_VARIABLES`. To add or change a
 * framework, edit this array, never the generated skill markdown and never the
 * scattered prose, then rebuild so every site updates in lockstep.
 *
 * Each framework MUST have a corresponding docs page at `docsPath`
 * (`bitfab-docs{docsPath}.mdx`); `frameworks.test.ts` enforces this.
 */
export interface Framework {
    /** Stable id, also the docs-page basename. */
    id: string;
    /** Human label used everywhere the framework is named. */
    label: string;
    /** Docs path the flow WebFetches when this framework is detected. */
    docsPath: string;
    /**
     * How the SDK hooks the framework:
     * - `callbackHandler`: a per-trace-function-keyed handler (takes a key arg);
     *   the recorded root replays by explicit key.
     * - `traceProcessor`: a process-wide processor (no key arg).
     * - `wrapper`: wraps individual calls (no key arg, not a root handler).
     */
    handlerKind: "callbackHandler" | "traceProcessor" | "wrapper";
    /** Noun used in prose, e.g. "callback handler", "tracing processor". */
    handlerNoun: string;
    /**
     * SDK method names that hook the framework. `py` is omitted for frameworks
     * that exist only in one ecosystem (e.g. the Vercel AI SDK is TypeScript
     * only): a missing `py` means "no Python integration", and every derived
     * builder and parity/harness test below drops Python for that framework.
     */
    handler: {
        ts: string;
        py?: string;
    };
    /** Optional identical-behavior aliases (e.g. LangChain-named for LangGraph). */
    aliasHandler?: {
        ts: string;
        py?: string;
    };
    /**
     * Optional keyed wrapper that records a REPLAYABLE root span around the run,
     * for frameworks whose primary `handler` does NOT (i.e. trace processors).
     * A trace processor captures a run's internals but records an empty-input
     * root; a root wrapper (e.g. OpenAI Agents `wrapRun` / `wrap_run`, returned
     * by these factory methods) opens a keyed root carrying the run input, so the
     * run replays by key with no hand-written `withSpan`/`@span`. Frameworks whose
     * `handler` already records the root (callback handlers) don't need this.
     */
    rootWrapper?: {
        ts: string;
        py?: string;
    };
    /**
     * Whether replay can mock (short-circuit) each ROLE of span this integration
     * AUTO-captures, fixed by how the SDK hooks that role:
     * - `"withSpan"`: the call runs THROUGH a Bitfab wrapper, so replay can return
     *   the recorded output. Mockable (though a `model_call` re-runs live by default).
     * - `"observed"`: the SDK only watches the call (callback handler, trace
     *   processor, stream, or collector) and re-runs it for real on replay. Not
     *   mockable.
     * Roles: `modelCall` = the LLM/model-call span; `child` = a nested
     * tool / retriever / external-read / side-effect span. Only roles the
     * integration actually emits are listed.
     *
     * The ROOT is deliberately excluded: it is never mockable regardless of
     * framework (it starts the replay), a universal rule the domain enforces
     * (`isTraceNodeMockable`), not a per-framework fact. This table is the default
     * for AUTO-captured spans ONLY, a call the user manually wraps in
     * `withSpan` / `@span` is always mockable. Source of truth for these values is
     * the SDK integration code (`langgraph.ts`, `openaiAgentSdk.ts`,
     * `claudeAgentSdk.ts`, `vercelAiSdk.ts`, `baml.ts`).
     */
    autoCapture: {
        modelCall?: "withSpan" | "observed";
        child?: "withSpan" | "observed";
    };
    /** Import/manifest detection signals, as ready-to-render markdown fragments. */
    signals: {
        ts: string;
        py?: string;
    };
}
export declare const FRAMEWORKS: readonly Framework[];
/** Comma list of every framework docs path. */
export declare function frameworkDocsPaths(): string;
/** The per-framework detection bullets for Instrument's detect-language step. */
export declare function frameworkDetectionBullets(): string;
/** The framework -> docs-page + handler-name routing for read-sdk-reference. */
export declare function frameworkReferenceList(): string;
/** "<label> via `tsHandler` / `pyHandler`" for each root-handler framework. */
export declare function handlerFrameworksWithMethods(): string;
/** Oxford list of root-handler framework labels. */
export declare function handlerFrameworkNames(): string;
/** Keyed-handler call refs for replay prose: '`py("key")`, ..., or the TS equivalents'. */
export declare function keyedHandlerKeyRefs(): string;
/** "<label> `handler`" for each keyed-replay framework (Python form, else TS). */
export declare function keyedHandlerExamples(): string;
/**
 * Oxford list of the framework integrations that record a replayable root with
 * no hand-written `withSpan`/`@span`: callback handlers (which record the
 * framework's own input as the root) and trace processors paired with their
 * root wrapper (OpenAI Agents `wrapRun`, which records the run input). These are
 * replayable as-is by key. A bare trace processor with no root wrapper is the
 * only root integration that is NOT replayable on its own (empty-input root).
 */
export declare function replayableRootHandlerNames(): string;
/**
 * Oxford list of the callback-handler frameworks only (the subset of replayable
 * roots whose own handler records the root, as opposed to trace processors that
 * need a run wrapper). Used to contrast the two replayable mechanisms in prose.
 */
export declare function callbackHandlerNames(): string;
/**
 * Oxford list of trace-processor framework labels. The processor captures a
 * run's internals but records an empty-input root, so it is replayable only when
 * paired with its root wrapper (`wrapRun` / `wrap_run`) or a hand-written
 * `withSpan`/`@span` root; a bare processor-only trace is not replayable.
 */
export declare function traceProcessorNames(): string;
/** Comma list of trace-processor root-wrapper methods: '`tsWrap` / `pyWrap`'. */
export declare function traceProcessorRootWrappers(): string;
/**
 * Per-framework mockability lookup for AUTO-captured spans, derived from each
 * framework's `autoCapture`. Answers "for a span this framework auto-captures,
 * can replay mock it?" The ROOT is excluded (never mockable, a universal rule),
 * and a call the user manually wraps in `withSpan`/`@span` is always mockable, so
 * this is the default for auto-captured spans only. Rendered as one bullet per
 * framework for the build-trace-plan / modify steps.
 */
export declare function frameworkMockabilityBullets(): string;
/**
 * Framework ids whose AUTO-captured model span is wrapped through `withSpan`
 * (so it IS mockable on replay). bitfab-web's `normalizeAndCorrectTree` backstop
 * must exempt exactly these from its "an auto span is not mockable" rule, or it
 * would wrongly mark them unmockable. `frameworks.test.ts` pins the backstop's
 * local `WITHSPAN_MODEL_FRAMEWORKS` set against this list so a new wrap-based
 * integration added here can't silently drift into over-marking.
 */
export declare function withSpanModelFrameworkIds(): string[];
/** The SDK grep patterns used to find existing instrumented trace functions. */
export declare function buildSdkPatterns(): string;
/**
 * Flow variables derived from the framework registry. Spread into a flow's
 * `variables` map so the registry single-sources every per-framework string.
 */
export declare const FRAMEWORK_VARIABLES: Record<string, string | Targetable<string>>;
